/** Maps Prisma scalar type names to TypeScript types. */
const PRISMA_TO_TS_TYPE: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  Decimal: 'string',
  BigInt: 'bigint',
  DateTime: 'string',
  Json: 'unknown',
  Bytes: 'string',
}

/**
 * Resolves a Prisma field type to its TypeScript representation.
 *
 * Scalar types are mapped via {@link PRISMA_TO_TS_TYPE}; enum types are
 * referenced by name; object (relation) types are skipped by callers before
 * reaching this function.
 */
export function toTsType(prismaType: string, kind: string): string {
  if (kind === 'enum') {
    return prismaType
  }
  return PRISMA_TO_TS_TYPE[prismaType] ?? 'unknown'
}

/** Produces a single line of a TypeScript interface body. */
export function fieldLine(name: string, tsType: string, optional: boolean, isList: boolean): string {
  const listSuffix = isList ? '[]' : ''
  const optionalMark = optional ? '?' : ''
  return `  ${name}${optionalMark}: ${tsType}${listSuffix}`
}

/** Indents every line of `text` by `spaces` spaces. */
export function indent(text: string, spaces: number): string {
  const pad = ' '.repeat(spaces)
  return text
    .split('\n')
    .map((line) => (line.trim() === '' ? '' : pad + line))
    .join('\n')
}

/** Converts a PascalCase model name to a camelCase resource name. */
export function toCamelCase(name: string): string {
  return name.charAt(0).toLowerCase() + name.slice(1)
}

/** Wraps a block of text in a documentation comment. */
export function docComment(text: string): string {
  return `/** ${text} */`
}

