import type { DMMF } from '@prisma/generator-helper'

import { docComment, fieldLine, toCamelCase, toTsType } from './template'

interface ScalarField {
  name: string
  tsType: string
  optional: boolean
  isList: boolean
  isId: boolean
  hasDefault: boolean
}

/**
 * Extracts scalar and enum fields from a DMMF model, skipping relation
 * (object) fields which have no direct REST representation.
 */
function extractScalarFields(model: DMMF.Model): ScalarField[] {
  const fields: ScalarField[] = []

  for (const field of model.fields) {
    if (field.kind === 'object') continue
    fields.push({
      name: field.name,
      tsType: toTsType(field.type, field.kind),
      optional: !field.isRequired,
      isList: field.isList,
      isId: field.isId,
      hasDefault: field.hasDefaultValue,
    })
  }

  return fields
}

function findIdField(fields: ScalarField[]): ScalarField | undefined {
  return fields.find((f) => f.isId)
}

/** Generates a TypeScript `interface` declaration for a single model. */
function generateModelInterface(model: DMMF.Model, fields: ScalarField[]): string {
  const lines = fields.map((f) => fieldLine(f.name, f.tsType, f.optional, f.isList))

  return [
    docComment(`Represents a ${model.name} record.`),
    `export interface ${model.name} {`,
    lines.join('\n'),
    '}',
  ].join('\n')
}

/**
 * Generates a `CreateInput` type that omits fields with defaults (like
 * auto-increment IDs and `@updatedAt` timestamps) and makes them optional.
 */
function generateCreateInput(model: DMMF.Model, fields: ScalarField[]): string {
  const lines = fields.map((f) => {
    const optional = f.optional || f.hasDefault
    return fieldLine(f.name, f.tsType, optional, f.isList)
  })

  return [
    docComment(`Input for creating a new ${model.name}.`),
    `export interface ${model.name}CreateInput {`,
    lines.join('\n'),
    '}',
  ].join('\n')
}

/** Generates an `UpdateInput` type where every field is optional. */
function generateUpdateInput(model: DMMF.Model, fields: ScalarField[]): string {
  const lines = fields.map((f) => fieldLine(f.name, f.tsType, true, f.isList))

  return [
    docComment(`Input for updating an existing ${model.name}.`),
    `export interface ${model.name}UpdateInput {`,
    lines.join('\n'),
    '}',
  ].join('\n')
}

/** Generates typed CRUD methods for a single model. */
function generateCrudMethods(model: DMMF.Model, fields: ScalarField[]): string {
  const name = model.name
  const resource = toCamelCase(name)
  const idField = findIdField(fields)
  const idType = idField?.tsType ?? 'string'

  return [
    docComment(`CRUD operations for the ${name} model.`),
    `export class ${name}Client {`,
    `  #baseUrl: string`,
    '',
    `  constructor(baseUrl: string) {`,
    `    this.#baseUrl = baseUrl`,
    `  }`,
    '',
    `  get #endpoint(): string {`,
    `    return \`\${this.#baseUrl}/${resource}\``,
    `  }`,
    '',
    generateFindMany(name),
    generateFindUnique(name, idType),
    generateCreate(name),
    generateUpdate(name, idType),
    generateDelete(name, idType),
    '}',
  ].join('\n')
}

function generateFindMany(name: string): string {
  return [
    `  ${docComment(`Retrieve all ${name} records.`)}`,
    `  async findMany(): Promise<${name}[]> {`,
    `    const response = await fetch(this.#endpoint)`,
    `    if (!response.ok) throw new Error(\`Failed to fetch ${name} list: \${response.statusText}\`)`,
    `    return response.json() as Promise<${name}[]>`,
    `  }`,
  ].join('\n')
}

function generateFindUnique(name: string, idType: string): string {
  return [
    '',
    `  ${docComment(`Retrieve a single ${name} by ID.`)}`,
    `  async findUnique(id: ${idType}): Promise<${name} | null> {`,
    `    const response = await fetch(\`\${this.#endpoint}/\${id}\`)`,
    `    if (response.status === 404) return null`,
    `    if (!response.ok) throw new Error(\`Failed to fetch ${name}: \${response.statusText}\`)`,
    `    return response.json() as Promise<${name}>`,
    `  }`,
  ].join('\n')
}

function generateCreate(name: string): string {
  return [
    '',
    `  ${docComment(`Create a new ${name} record.`)}`,
    `  async create(data: ${name}CreateInput): Promise<${name}> {`,
    `    const response = await fetch(this.#endpoint, {`,
    `      method: 'POST',`,
    `      headers: { 'Content-Type': 'application/json' },`,
    `      body: JSON.stringify(data),`,
    `    })`,
    `    if (!response.ok) throw new Error(\`Failed to create ${name}: \${response.statusText}\`)`,
    `    return response.json() as Promise<${name}>`,
    `  }`,
  ].join('\n')
}

function generateUpdate(name: string, idType: string): string {
  return [
    '',
    `  ${docComment(`Update an existing ${name} by ID.`)}`,
    `  async update(id: ${idType}, data: ${name}UpdateInput): Promise<${name}> {`,
    `    const response = await fetch(\`\${this.#endpoint}/\${id}\`, {`,
    `      method: 'PATCH',`,
    `      headers: { 'Content-Type': 'application/json' },`,
    `      body: JSON.stringify(data),`,
    `    })`,
    `    if (!response.ok) throw new Error(\`Failed to update ${name}: \${response.statusText}\`)`,
    `    return response.json() as Promise<${name}>`,
    `  }`,
  ].join('\n')
}

function generateDelete(name: string, idType: string): string {
  return [
    '',
    `  ${docComment(`Delete a ${name} by ID.`)}`,
    `  async delete(id: ${idType}): Promise<void> {`,
    `    const response = await fetch(\`\${this.#endpoint}/\${id}\`, {`,
    `      method: 'DELETE',`,
    `    })`,
    `    if (!response.ok) throw new Error(\`Failed to delete ${name}: \${response.statusText}\`)`,
    `  }`,
  ].join('\n')
}

/** Generates the combined `RestClient` class that exposes all model clients. */
function generateRestClient(models: readonly DMMF.Model[]): string {
  const properties = models.map((model) => {
    const resource = toCamelCase(model.name)
    return `  ${resource}: ${model.name}Client`
  })

  const assignments = models.map((model) => {
    const resource = toCamelCase(model.name)
    return `    this.${resource} = new ${model.name}Client(baseUrl)`
  })

  return [
    docComment('Typed REST API client generated from the Prisma schema.'),
    `export class RestClient {`,
    properties.join('\n'),
    '',
    `  constructor(baseUrl: string) {`,
    assignments.join('\n'),
    `  }`,
    '}',
  ].join('\n')
}

/** Generates enum type declarations. */
function generateEnum(enumDef: DMMF.DatamodelEnum): string {
  const values = enumDef.values.map((v) => `  | '${v.name}'`).join('\n')
  return [docComment(`Enum type for ${enumDef.name}.`), `export type ${enumDef.name} =`, values].join('\n')
}

/**
 * Main generation entry point. Produces the full `rest-client.ts` source from
 * the DMMF document.
 */
export function generate(dmmf: DMMF.Document): string {
  const models = dmmf.datamodel.models
  const enums = dmmf.datamodel.enums

  const sections: string[] = [
    '// ---------------------------------------------------------------',
    '// REST Client generated by @prisma/generator-rest-client',
    '// Do not edit manually.',
    '// ---------------------------------------------------------------',
    '',
  ]

  for (const enumDef of enums) {
    sections.push(generateEnum(enumDef))
    sections.push('')
  }

  for (const model of models) {
    const fields = extractScalarFields(model)

    sections.push(generateModelInterface(model, fields))
    sections.push('')
    sections.push(generateCreateInput(model, fields))
    sections.push('')
    sections.push(generateUpdateInput(model, fields))
    sections.push('')
    sections.push(generateCrudMethods(model, fields))
    sections.push('')
  }

  sections.push(generateRestClient(models))
  sections.push('')

  return sections.join('\n')
}

